UPDATE public.questions SET
  stimulus_text = 'The history of the United States is filled with stories of individuals who, by taking risks, transformed the country. Some of these individuals were inventors, others were entrepreneurs, and still others were activists.  The entrepreneur Henry Ford, for example, changed the way people traveled by perfecting a system of mass production for automobiles.',
  question_text = 'Which choice provides the most effective transition between the two sentences? ',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"As a result,. This choice completes the idea as a full sentence rather than a fragment.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"For instance,. This choice completes the idea as a full sentence rather than a fragment.","is_correct":true,"explanation":"The most effective transition is \"For instance,\" because it introduces an example that illustrates the point made in the previous sentence.  The previous sentence states that some individuals who took risks transformed the country, and the example of Henry Ford illustrates this point. The other choi. Choice B matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"In addition,. This choice completes the idea as a full sentence rather than a fragment.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"Therefore,. This choice completes the idea as a full sentence rather than a fragment.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'B',
  explanation = 'The most effective transition is "For instance," because it introduces an example that illustrates the point made in the previous sentence.  The previous sentence states that some individuals who took risks transformed the country, and the example of Henry Ford illustrates this point. The other choices are less effective. "As a result" suggests a cause-and-effect relationship, which is not present in the two sentences. "In addition" suggests that the example is additional information to the previous sentence, but the example is actually an illustration of the previous sentence. "Therefore" suggests a conclusion, but the example is not a conclusion. The passage states that "The history of the United States is filled with stories of individuals who, by taking risks, transformed the country. So…", which is the textual anchor for eliminating weaker choices. Choice B is correct because it aligns with that evidence: For instance,. This choice completes the idea as a full sentence rather than a fragment.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"section":"english","skill_id":"FSS","domain_id":"conventions","opensat_index":305,"opensat_domain":"Standard English Conventions","opensat_raw_id":"random_id_c7","opensat_difficulty":"Hard","english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.919Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
